class Solution:
    def palindromePartition(self, s: str, k: int) -> int:
        n = len(s)
        dp = [[0] * n for _ in range(n)]
        for i in range(n):
            dp[i][i] = 0
        for length in range(2, n + 1):
            for i in range(n - length + 1):
                j = i + length - 1
                if s[i] != s[j]:
                    dp[i][j] = dp[i + 1][j - 1] + 1
                else:
                    dp[i][j] = dp[i + 1][j - 1]
        res = dp[0][n - 1]
        for i in range(1, n):
            if dp[0][i - 1] + dp[i][n - 1] > k:
                return res + i
            res = dp[0][i - 1] + dp[i][n - 1]
        return res
